"""
MKT Original Language Commentary — Psalms chapters 68–70
Run: python3 scripts/zc-original-psalms-68-70.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json (contested terms)
- data/translation/draft/mediating/psalms.json (MKT text for quoting)

Key decisions in this range:
- Ps 68:4: ʿărābôt rendered "heavens" — the polemic against Baal's Ugaritic title
  "rider on the clouds" (rkb ʿrpt) is explicit; JAH = contracted form of YHWH (יָהּ)
- Ps 68:18/Eph 4:8: MT reads "you received gifts from men" (lāqaḥtā mattānôt bāʾādām);
  Paul in Eph 4:8 reverses to "gave gifts to men" — a midrashic application of Christ's
  ascension to distributing Spirit-gifts; both readings noted
- Ps 69: the most cited lament psalm in the NT; all major citations noted
  (v4/John 15:25; v9/John 2:17; v21/Matt 27:34,48; v22/Rom 11:9-10; v25/Acts 1:20)
- Ps 70: near-duplicate of Ps 40:13-17; the lĕhazzkîr superscription treated as
  a liturgical "emergency" marker; the compression vs. Ps 40 is itself significant
- Throughout: terminology consistent with previous Psalms original scripts
  (ḥesed, ʿōz, nāpesh, etc. in prior script register)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 68-70 — the great processional victory hymn
#   with the Num 10:35 ark-formula and Eph 4:8 ascent citation (Ps68); the most
#   NT-quoted individual lament psalm (Ps69); and the compressed emergency
#   petition that near-duplicates Ps 40:13-17 (Ps70).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(68,71)])"

PSALMS = {
  "68": {
    "1": '<p>The superscription assigns Psalm 68 to David as both a psalm (<em>mizmôr</em>) and a song (<em>shîr</em>). The opening words are a direct quotation of the ark-setting-out formula from Num 10:35: <strong>יָקוּם אֱלֹהִים יָפוּצוּ אוֹיְבָיו</strong> (<em>yāqûm ʾĕlōhîm yāpûṣû ʾôyĕbāyw</em>, "Let God arise, let his enemies be scattered"). In Numbers the formula was spoken by Moses each time the ark moved through the wilderness; its citation here signals that Psalm 68 is a processional hymn accompanying the ark into the sanctuary. <em>Qûm</em> (to arise — the standing-up from rest of a king about to act): God roused to march. <strong>וְיָנוּסוּ מְשַׂנְאָיו מִפָּנָיו</strong> (<em>wĕyānûsû mĕśānʾāyw mippānāyw</em>, "let those who hate him flee before him") — the enemies in full flight before the advancing divine presence. The ark was the visible throne of the invisible God; when it moved, the enemies\' flight was anticipated as already accomplished.</p>',
    "2": '<p>Two similes for the dissolution of the wicked: <strong>כְּהִנְדֹּף עָשָׁן תִּנְדֹּף</strong> (<em>kĕhindōp ʿāshān tindōp</em>, "as smoke is dispersed by the wind, disperse them") — <em>nādap</em>: to blow away, to scatter (the insubstantial enemy driven off by a gust). <strong>כְּהִמֵּס דּוֹנַג מִפְּנֵי-אֵשׁ</strong> (<em>kĕhimmês dônag mippĕnê-ʾêsh</em>, "as wax melts before fire") — <em>māsas</em> (niphal: to melt, to dissolve): wax before fire is the image of swift, irreversible dissolution. Both similes are chosen for their speed: smoke is gone in a gust; wax melts at the fire\'s approach. The enemies are already as insubstantial as smoke, already as fugitive as wax. <strong>יֹאבְדוּ רְשָׁעִים מִפְּנֵי אֱלֹהִים</strong> (<em>yōʾbĕdû rĕshāʿîm mippĕnê ʾĕlōhîm</em>, "so let the wicked perish before God") — <em>ʾābad</em>: to be destroyed (as in Ps 1:6 — the way of the wicked perishes).</p>',
    "3": '<p><strong>וְצַדִּיקִים יִשְׂמְחוּ יַעַלְצוּ לִפְנֵי אֱלֹהִים</strong> (<em>wĕṣaddîqîm yiśmĕḥû yaʿalṣû lipnê ʾĕlōhîm</em>, "But let the righteous be glad and rejoice before God") — two joy verbs: <em>śāmaḥ</em> (to be glad — the general term) and <em>ʿālaṣ</em> (to exult, to leap with joy — the more physical, dancing delight). <strong>וְיָשִׂישׂוּ בְשִׂמְחָה</strong> (<em>wĕyāśîśû bĕśimḥāh</em>, "let them celebrate with great joy") — <em>śîś</em> (to exult greatly — Isa 61:10: "I will greatly rejoice in the LORD"). Three joy terms accumulate: the righteous response to God\'s arising is an escalating, irrepressible delight. Contrast with the enemies\' three-stage dissolution (smoke, wax, perishing).</p>',
    "4": '<p><strong>שִׁירוּ לֵאלֹהִים זַמְּרוּ שְׁמוֹ</strong> (<em>shîrû lêʾlōhîm zammĕrû shĕmô</em>, "Sing to God, sing praises to his name") — the double call to song: <em>shîr</em> (vocal song) and <em>zāmar</em> (instrumental praise). <strong>סֹלּוּ לָרֹכֵב בָּעֲרָבוֹת</strong> (<em>sōllû lārōkêb bāʿărābôt</em>, "exalt him who rides upon the ʿărābôt") — <em>sālal</em>: to heap up, to lift up, to make a highway for. <em>Rōkêb bāʿărābôt</em>: "rider on the ʿărābôt" — "the heavens" (cf. Deut 33:26). This epithet directly parallels the Ugaritic divine title <em>rkb ʿrpt</em> ("rider on the clouds") applied to Baal in Canaanite literature — the Psalmist claims that title exclusively for YHWH, performing a polemical displacement of the storm-god. <strong>בְּיָהּ שְׁמוֹ</strong> (<em>bĕYāh shĕmô</em>, "the LORD [JAH] is his name") — <em>Yāh</em>: the contracted form of YHWH (יָהּ), appearing independently only here and in the <em>hallĕlû-Yāh</em> formula. The short divine name asserts the identity of the heavens-rider with Israel\'s covenant God.</p>',
    "5": '<p><strong>אֲבִי יְתוֹמִים וְדַיַּן אַלְמָנוֹת</strong> (<em>ʾăbî yĕtômîm wĕdayyān ʾalmānôt</em>, "a father of orphans and a defender of widows") — two divine titles for those without natural protectors: <em>ʾāb</em> (father) to the <em>yātôm</em> (orphan — the fatherless); <em>dayyān</em> (judge/defender/advocate — from <em>dîn</em>: to govern, to plead a cause, to defend in court) for the <em>ʾalmānāh</em> (widow — the one without a husband-protector). Together they define the divine character as the advocate for the legally and socially voiceless — the theme of Exod 22:22-24; Deut 10:18; Isa 1:17. <strong>אֱלֹהִים בִּמְעוֹן קָדְשׁוֹ</strong> (<em>ʾĕlōhîm bimʿôn qodshô</em>, "God in his holy dwelling") — from the holy dwelling above, God attends to those below who have no earthly advocate.</p>',
    "6": '<p><strong>אֱלֹהִים מוֹשִׁיב יְחִידִים בַּיְתָה</strong> (<em>ʾĕlōhîm môshîb yĕḥîdîm baytāh</em>, "God gives the isolated a home to belong to") — <em>yāḥîd</em>: solitary, isolated, alone (the single one without family network). <em>Môshîb</em> (hiphil participle: the one who settles, who causes to dwell): God as the divine settlor who plants the isolated into a household. <strong>מוֹצִיא אֲסִירִים בַּכּוֹשָׁרוֹת</strong> (<em>môṣîʾ ʾăsîrîm bakkôshārôt</em>, "he brings prisoners out into freedom") — <em>bakkôshārôt</em>: possibly "with singing/with prosperity" (from <em>kāshar</em>: to prosper) — the liberation accompanied by flourishing. <strong>אַךְ סוֹרְרִים שָׁכְנוּ צְחִיחָה</strong> (<em>ʾak sôrĕrîm shākĕnû ṣĕḥîḥāh</em>, "but the rebellious dwell in a parched land") — <em>sôrēr</em>: the stubborn rebel (Deut 21:18); <em>ṣĕḥîḥāh</em>: a scorched, sun-baked waste — the habitat that mirrors the spiritual condition of those who resist the settling God.</p>',
    "7": '<p><strong>אֱלֹהִים בְּצֵאתְךָ לִפְנֵי עַמֶּךָ</strong> (<em>ʾĕlōhîm bĕṣêtĕkā lipnê ʿammekā</em>, "O God, when you went out before your people") — the theophany-march begins: God going before Israel (Exod 13:21-22; Num 10:33). <strong>בְּצַעְדְּךָ בִישִׁימוֹן סֶלָה</strong> (<em>bĕṣaʿdĕkā bîshîmôn selāh</em>, "when you marched through the wilderness") — <em>ṣāʿad</em>: to march, to stride (the measured military step of a warrior); <em>yĕshîmôn</em>: the desolate wilderness (Num 21:20). The phrase closely parallels the Song of Deborah (Judg 5:4-5): "LORD, when you went out from Seir... the earth trembled." Both texts preserve memory of the same wilderness march. <em>Selāh</em> marks the pause before the theophany description.</p>',
    "8": '<p><strong>אֶרֶץ רָעָשָׁה אַף-שָׁמַיִם נָטְפוּ</strong> (<em>ʾereṣ rāʿāshāh ʾap-shāmayim nāṭĕpû</em>, "the earth shook, and the heavens poured down rain") — <em>rāʿash</em>: to quake, to tremble (the seismic response to divine approach — Ps 77:18; Judg 5:4); <em>nāṭap</em>: to drip, to pour down. <strong>מִפְּנֵי אֱלֹהִים זֶה סִינַי</strong> (<em>mippĕnê ʾĕlōhîm zeh sînay</em>, "at the presence of God — even Sinai itself") — the parenthetical identification: Sinai is the paradigm-theophany, and all else trembles by reference to it. <strong>מִפְּנֵי אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל</strong> (<em>mippĕnê ʾĕlōhîm ʾĕlōhê yiśrāʾêl</em>, "at the presence of God, the God of Israel") — the full divine title anchors the cosmic trembling in covenant history: this is not generic deity but Israel\'s covenant God.</p>',
    "9": '<p><strong>גֶּשֶׁם נְדָבוֹת תָּנִיף אֱלֹהִים</strong> (<em>geshem nĕdābôt tānîp ʾĕlōhîm</em>, "You sent an abundant rain, O God") — <em>nĕdābôt</em>: freewill-offerings, voluntary gifts (from <em>nādab</em>: to give freely without compulsion — as in Exod 25:2: the freewill offering for the tabernacle). The rain described as a <em>nĕdābāh</em> is a divine gift given out of liberality, not obligation. <em>Nûp</em> (hiphil: to wave, to shake loose): God scattering the rain from the clouds. <strong>נַחֲלָתְךָ וְנִלְאָה אַתָּה כוֹנַנְתָּהּ</strong> (<em>naḥălātĕkā wĕnilʾāh ʾattāh kônantāh</em>, "you restored your weary inheritance") — <em>nālaʾ</em>: to be weary, exhausted; <em>kûn</em> (polel: to establish firmly, to restore): God re-establishing the exhausted inheritance. The "inheritance" (<em>naḥălāh</em>) is the covenant people — weary from the wilderness and needing divine restoration.</p>',
    "10": '<p><strong>חַיָּתְךָ יָשְׁבוּ-בָהּ</strong> (<em>ḥayyātĕkā yāshĕbû-bāh</em>, "Your congregation settled in the land") — <em>ḥayyāh</em>: a community, a living group (the living community of the covenant — from <em>ḥāyāh</em>: to live). <strong>תָּכִין בְּטוֹבָתְךָ לֶעָנִי אֱלֹהִים</strong> (<em>tākîn bĕṭôbātĕkā leʿānî ʾĕlōhîm</em>, "in your goodness, O God, you provided for the needy") — <em>kûn</em> (hiphil: to establish, to prepare, to provide — as a host sets a table for a guest): God\'s goodness (<em>ṭôbāh</em>) as the instrument of provision for the <em>ʿānî</em> (the needy, the afflicted — the one who is bent down by want). The land settlement is not merely a political event but an act of divine provision for those who depended entirely on God\'s goodness.</p>',
    "11": '<p><strong>אֲדֹנָי יִתֶּן-אֹמֶר</strong> (<em>ʾădōnāy yittên-ʾōmer</em>, "The Lord gave the word") — <em>ʾōmer</em>: a word, a saying (the divine proclamation that sets the victory in motion). <strong>הַמְבַשְּׂרוֹת צָבָא רָב</strong> (<em>hamĕbaśśĕrôt ṣābāʾ rāb</em>, "great was the army of women who announced the victory") — <em>bāśar</em> (piel feminine plural participle: women announcing/heralding good news): the <em>mĕbaśśĕrôt</em> are women heralds of victory (as in Exod 15:20-21 where Miriam leads the women in the victory song; 1 Sam 18:6-7 where women with timbrels celebrate David\'s victories). <em>Ṣābāʾ rāb</em>: a great army of female heralds — the victory announcement is carried by an army of women. The divine word given; the women\'s proclamation as the immediate response.</p>',
    "12": '<p><strong>מַלְכֵי צְבָאוֹת יִדֹּדוּן יִדֹּדוּן</strong> (<em>malkê ṣĕbāʾôt yiddōdûn yiddōdûn</em>, "The kings of armies fled in haste") — the doubled <em>yiddōdûn</em> marks the frantic speed of the kings\' flight. <strong>וּנְוַת-בַּיִת תְּחַלֵּק שָׁלָל</strong> (<em>ûnĕwat-bayit tĕḥallêq shālāl</em>, "she who stayed at home shared in the plunder") — <em>nĕwat-bayit</em>: "the one who stays at the house" — the woman at home, not on the battlefield, yet given a share in the plunder. This is the custom of Num 31:27: the spoil divided between fighters and the rest of the community. Even those who did not fight receive God\'s victory-gift.</p>',
    "13": '<p>The verse is notoriously difficult. <strong>אִם-תִּשְׁכְּבוּן בֵּין שְׁפַתָּיִם</strong> (<em>ʾim-tishkĕbûn bên shĕpattayim</em>, "even if you once lay among the sheepfolds") — <em>shĕpattayim</em>: possibly sheepfolds, saddlebags, or the two sides of something — the word\'s meaning is uncertain. The imagery suggests a former low or resting state. <strong>כַּנְפֵי יוֹנָה נֶחְפָּה בַכֶּסֶף</strong> (<em>kanpê yônāh neḥpāh bakkesep</em>, "the wings of a dove covered with silver") — the dove with silver-covered wings: possibly Israel emerging from disgrace into the glory of deliverance (Ps 74:19 where the dove represents the community). The contrast is between resting in lowly sheepfolds and the subsequent shining of silver-and-gold wings. <strong>וְאֶבְרוֹתֶיהָ בִּירַקְרַק חָרוּץ</strong> (<em>wĕʾebrôtêhā bîraqraq ḥārûṣ</em>, "her feathers with yellow gold") — <em>yrq-yrq</em>: reduplication for gleaming yellowish-green; <em>ḥārûṣ</em>: refined gold. The image of a dove whose plain feathers have been transformed by divine victory into gleaming gold — glory following humiliation.</p>',
    "14": '<p><strong>בְּפָרֵשׂ שַׁדַּי מְלָכִים בָּהּ</strong> (<em>bĕpārêś shadday mĕlākîm bāh</em>, "When the Almighty scattered kings throughout the land") — <em>Shadday</em>: the Almighty (the patriarchal divine name — Gen 17:1; 28:3); <em>pāraś</em>: to spread out, to scatter. <strong>תַּשְׁלֵג בְּצַלְמוֹן</strong> (<em>tashleg bĕṣalmôn</em>, "it snowed on Zalmon") — <em>shālag</em> (hiphil: to snow — the only occurrence of the hiphil of <em>shālag</em>); <em>Ṣalmôn</em>: a dark or shaded mountain (near Shechem — Judg 9:48). The sudden whitening of the dark mountain may image the transformation of the enemy-landscape by divine power — the darkness of enemy territory blanched white by the Almighty\'s intervention.</p>',
    "15": '<p><strong>הַר-אֱלֹהִים הַר-בָּשָׁן</strong> (<em>har-ʾĕlōhîm har-bāshān</em>, "The mountain of God is like the mountain of Bashan") — an exclamation addressed to the Bashan range (including Hermon — 9,232 feet), the most impressive mountain system in the region. <strong>הַר-גַּבְנֻנִּים הַר-בָּשָׁן</strong> (<em>har-gabnunnîm har-bāshān</em>, "a high, many-peaked mountain, like the mountain of Bashan") — <em>gabnunnîm</em>: many-ridged, jagged-peaked (a word for the serrated ridge-line of a great mountain range). The verse sets up the contrast to follow: Bashan is magnificent, many-peaked, and seemingly the natural choice for a divine dwelling — yet God chose differently.</p>',
    "16": '<p><strong>לָמָּה תְּרַצְּדוּן הָרִים גַּבְנֻנִּים</strong> (<em>lāmmāh tĕraṣṣĕdûn hārîm gabnunnîm</em>, "Why do you look with envy, O many-peaked mountains?") — <em>rāṣad</em>: to look askance, to eye with jealousy (a rare verb — the mountains personified as looking with competitive envy at Zion). <strong>הָהָר חָמַד אֱלֹהִים לְשִׁבְתּוֹ</strong> (<em>hāhār ḥāmad ʾĕlōhîm lĕshibtô</em>, "This is the mountain that God desired for his dwelling") — <em>ḥāmad</em>: to desire, to covet, to delight in (the same root as the Tenth Commandment\'s <em>lōʾ taḥmōd</em>). God\'s sovereign desire chose Zion — the smaller, less dramatic hill — over the imposing Bashan range. <strong>אַף-יְהוָה יִשְׁכֹּן לָנֶצַח</strong> (<em>ʾap-yĕhwāh yishkōn lāneṣaḥ</em>, "the LORD will dwell there forever") — the permanence of the divine choice: Zion as the eternal dwelling, not by geological majesty but by divine election (Deut 7:7-8: God chose Israel not because of its greatness but because of love).</p>',
    "17": '<p><strong>רֶכֶב אֱלֹהִים רִבֹּתַיִם אַלְפֵי שִׁנְאָן</strong> (<em>rekeb ʾĕlōhîm ribbōtayim ʾalpê shinʾān</em>, "The chariots of God are twenty thousands, thousands upon thousands") — <em>ribbōtayim</em>: the dual of ten-thousand = twenty thousand; <em>ʾalpê shinʾān</em>: "thousands upon thousands" (the exact meaning of <em>shinʾān</em> is debated: possibly "repeated," "of angels," or "of the terrifying"). The massive enumeration of the divine army dwarfs any human force. <strong>אֲדֹנָי בָם סִינַי בַּקֹּדֶשׁ</strong> (<em>ʾădōnāy bām sînay baqqōdesh</em>, "the Lord is among them — as in Sinai, in the holy place") — the key theological claim: the same divine presence that appeared at Sinai in the wilderness is now present in Zion\'s sanctuary. Sinai-holiness and Zion-holiness are continuous; the God of the wilderness theophany has brought his throne permanently to Jerusalem.</p>',
    "18": '<p>The most theologically freighted verse in the psalm and the one cited in the NT. <strong>עָלִיתָ לַמָּרוֹם שָׁבִיתָ שֶּׁבִי</strong> (<em>ʿālîtā lammārôm shābîtā shebî</em>, "You have ascended to the heights, leading a train of captives") — <em>ʿālāh</em>: to ascend; <em>shābāh shebî</em>: the cognate-accusative construction "you led captivity captive" (the absolute internal object — emphasizing the completeness and finality of the victory). The image is of the victorious king ascending to his throne after battle, bringing the conquered enemies as the trophy of his triumph. <strong>לָקַחְתָּ מַתָּנוֹת בָּאָדָם</strong> (<em>lāqaḥtā mattānôt bāʾādām</em>, "you have received tribute from men") — the MT reads "received/taken" (<em>lāqaḥtā</em>): the victorious king receives tribute. Eph 4:8 quotes this with "he gave gifts to men" (<em>ἔδωκεν δόματα τοῖς ἀνθρώποις</em>) — reversing the direction. Paul\'s reading either follows a targum tradition or applies a midrashic technique: the ascended Christ distributes to the church what he received; the "giving" is the Spirit\'s gifts given through the ascended Lord. The reversal is deliberate: Christ did not ascend to hoard the tribute but to distribute the Spirit as gifts. <strong>אַף סוֹרְרִים לִשְׁכֹּן יָהּ אֱלֹהִים</strong> (<em>ʾap sôrĕrîm lishkōn Yāh ʾĕlōhîm</em>, "yes, even the rebellious — that the LORD God might dwell there") — the extraordinary extension: the victory benefits even the formerly rebellious.</p>',
    "19": '<p><strong>בָּרוּךְ אֲדֹנָי יוֹם יוֹם</strong> (<em>bārûk ʾădōnāy yôm yôm</em>, "Blessed be the Lord, who day after day carries our burdens for us") — the distributive repetition <em>yôm yôm</em> (day day = every single day): the divine carrying is not a one-time rescue but a continuous, daily burden-bearing. <strong>יַעֲמָס-לָנוּ הָאֵל יְשׁוּעָתֵנוּ סֶלָה</strong> (<em>yaʿămās-lānû hāʾêl yĕshûʿātênû selāh</em>, "the God of our salvation carries our loads") — <em>ʿāmas</em>: to load, to carry a burden as a beast of burden carries a pack (Isa 46:1-4: "I have carried you from before your birth... I will carry and will save"). God compared to a beast of burden lovingly carrying what his people cannot carry themselves. The warrior-God of the processional is also the daily burden-bearer. <em>Selāh</em>.</p>',
    "20": '<p><strong>הָאֵל לָנוּ אֵל לְמוֹשָׁעוֹת</strong> (<em>hāʾêl lānû ʾêl lĕmôshāʿôt</em>, "Our God is the God of deliverances") — <em>môshāʿôt</em>: plural of salvation/deliverance: multiple deliverances, the accumulated repertoire of divine rescues. The God of one salvation would be remarkable; the God of deliverances (plural) is the God of a track record. <strong>וְלֵיהוִה אֲדֹנָי לַמָּוֶת תּוֹצָאוֹת</strong> (<em>wĕlayĕhwāh ʾădōnāy lammāwet tôṣāʾôt</em>, "and to the LORD, the Lord, belong the ways of escape from death") — <em>tôṣāʾôt</em>: exits, escape routes (from <em>yāṣāʾ</em>: to go out). Even from death — the ultimate closure — God has exits. The plural <em>tôṣāʾôt</em> suggests multiple escape routes that God holds: he who controls even death\'s exits controls everything.</p>',
    "21": '<p><strong>אַךְ-אֱלֹהִים יִמְחַץ רֹאשׁ אֹיְבָיו</strong> (<em>ʾak-ʾĕlōhîm yimḥaṣ rōʾsh ʾôyĕbāyw</em>, "But God will crush the head of his enemies") — <em>māḥaṣ</em>: to shatter, to smash (as in Num 24:17: the star from Jacob "shall crush the foreheads of Moab"; Ps 110:6: "he will shatter heads over the wide earth"). <strong>קָדְקֹד שֵׂעָר מִתְהַלֵּךְ בַּאֲשָׁמָיו</strong> (<em>qodqōd śēʿār mithallêk bāʾăshāmāyw</em>, "the proud scalp of those who persist in their guilt") — <em>qodqōd</em>: the crown/top of the head; <em>śēʿār</em>: hairy (the flowing hair of the unashamed proud — possibly the warrior\'s long hair). <em>Mithallêk bāʾăshāmāyw</em>: "walking about in their guilt" — those who continue in their offenses without turning. The crushing is directed specifically at the proud who persist in guilt rather than repenting.</p>',
    "22": '<p><strong>אָמַר אֲדֹנָי מִבָּשָׁן אָשִׁיב</strong> (<em>ʾāmar ʾădōnāy mibbāshān ʾāshîb</em>, "The Lord declared, \'I will bring them back from Bashan\'") — the divine speech: bringing back the enemy from Bashan (the far territory east of the Jordan — a general term for the remote places of enemy retreat). <strong>אָשִׁיב מִמְּצֻלוֹת יָם</strong> (<em>ʾāshîb mimmĕṣûlôt yām</em>, "I will bring my people back from the depths of the sea") — the two extreme geographies: the high territory of Bashan and the depths of the sea. No enemy refuge is beyond God\'s reach; no oppressed people too deeply submerged to be retrieved. The motif echoes Amos 9:2-3: no depth or height places anyone beyond God\'s hand.</p>',
    "23": '<p><strong>לְמַעַן תִּמְחַץ רַגְלְךָ בְּדָם</strong> (<em>lĕmaʿan timḥaṣ raglĕkā bĕdām</em>, "so that your foot will be stained in the blood of your enemies") — a graphic battle image: the victory so complete that the returning warrior\'s foot is bloodied by the field of the slain. <strong>לְשׁוֹן כְּלָבֶיךָ מֵאֹיְבִים מִנֵּהוּ</strong> (<em>lĕshôn kĕlābêkā mêʾōyĕbîm minnehû</em>, "and the tongues of your dogs will have their share") — the dogs licking the blood of the battlefield slain (as in 1 Kgs 22:38; 21:19). The image does not celebrate cruelty but the completeness of divine vindication over the enemy: even the scavenging dogs are fed by the thoroughness of the victory.</p>',
    "24": '<p><strong>רָאוּ הֲלִיכוֹתֶיךָ אֱלֹהִים</strong> (<em>rāʾû hălîkôtêkā ʾĕlōhîm</em>, "People have witnessed your processions, O God") — <em>hălîkāh</em>: procession, march (from <em>hālak</em>: to walk/go). The psalm shifts from narrative of past victories to the present liturgical procession. <strong>הֲלִיכוֹת אֵלִי מַלְכִּי בַקֹּדֶשׁ</strong> (<em>hălîkôt ʾêlî malkî baqqōdesh</em>, "the processions of my God, my King, into the holy place") — the processional into the sanctuary: the ark brought into the Jerusalem temple, carrying with it the memory of all the Sinai and wilderness marches now culminating in permanent holy dwelling. The worshiper\'s personal claim: "my God, my King."</p>',
    "25": '<p><strong>קִדְּמוּ שָׁרִים אַחַר נֹגְנִים</strong> (<em>qiddĕmû shārîm ʾaḥar nōgĕnîm</em>, "The singers lead the procession; behind them come the musicians") — <em>qādam</em> (piel: to go before, to lead): the singers at the head; <em>nōgĕnîm</em>: players of stringed instruments (from <em>nāgan</em>: to play — 1 Sam 16:16-18 for David playing for Saul). <strong>בְּתוֹךְ עֲלָמוֹת תּוֹפֵפוֹת</strong> (<em>bĕtôk ʿălāmôt tôpĕpôt</em>, "among them, young women playing tambourines") — <em>ʿălāmôt</em>: young women (as in 1 Sam 18:6-7; Exod 15:20: Miriam and the women with timbrels); <em>tôpēp</em>: to beat the tambourine. The procession composition: male singers leading, then string players, with young women with timbrels among them — the full worship orchestra in procession.</p>',
    "26": '<p><strong>בְּמַקְהֵלוֹת בָּרְכוּ אֱלֹהִים</strong> (<em>bĕmaqhêlôt bārĕkû ʾĕlōhîm</em>, "Bless God in the great assembly") — <em>maqhêlôt</em>: congregations, choral assemblies (from <em>qāhal</em>: the assembled congregation). The call to corporate blessing (<em>bārak</em>): the assembled multitude joining in the doxology. <strong>אֲדֹנָי מִמְּקוֹר יִשְׂרָאֵל</strong> (<em>ʾădōnāy mimmĕqôr yiśrāʾêl</em>, "praise the LORD, all you who come from the fountain of Israel") — <em>māqôr</em>: spring, fountain, source (Israel\'s patriarchal origin — the fountain from which all Israel flows). The comprehensive summons: all who trace their origin to the source of Israel are called to join the assembly-blessing.</p>',
    "27": '<p><strong>שָׁם בִּנְיָמִן צָעִיר רֹדֵם</strong> (<em>shām binyāmîn ṣāʿîr rōdêm</em>, "There is Benjamin, the youngest, leading the way") — <em>ṣāʿîr</em>: the youngest, the smallest (the tribe of Benjamin, the last-born son of Jacob). Benjamin paradoxically leads despite being the smallest. The tribes named in the processional: <strong>שָׂרֵי יְהוּדָה רִגְמָתָם</strong> (<em>śārê yĕhûdāh rigmātām</em>, "the princes of Judah in their bright company") — <em>rigmāh</em>: a heap, a crowd (a gathered throng). Judah, Zebulun, Naphtali — a representative sample of the northern and southern tribes together, united in the processional worship. The tribal gathering in Jerusalem is the enacted unity of what will be divided under Solomon\'s successors.</p>',
    "28": '<p><strong>צִוָּה אֱלֹהֶיךָ עֻזֶּךָ</strong> (<em>ṣiwwāh ʾĕlōhêkā ʿuzzekā</em>, "Your God has commanded your strength") — <em>ṣāwāh</em>: to command, to ordain (God having already ordained and established the people\'s strength — the strength is not self-generated but divinely decreed). <strong>עוּזָּה אֱלֹהִים זוּ פָּעַלְתָּ לָּנוּ</strong> (<em>ʿûzzāh ʾĕlōhîm zû pāʿaltā llānû</em>, "show your strength, O God, in what you have already begun for us") — the petition: not for new power but for the continuation and display of what God has already done. The perfect <em>pāʿaltā</em> ("what you have done") grounds the imperative <em>ʿûzzāh</em> ("show strength") — past acts are the basis for present appeal.</p>',
    "29": '<p><strong>מֵהֵיכָלֶךָ עַל-יְרוּשָׁלִָם</strong> (<em>mêhêkālekā ʿal-yĕrûshālāim</em>, "Because of your temple in Jerusalem") — the temple as the address from which tribute is commanded: the temple\'s presence in Jerusalem is the magnet drawing the kings. <strong>לְךָ יוֹבִילוּ מְלָכִים שָׁי</strong> (<em>lĕkā yôbîlû mĕlākîm shāy</em>, "kings will bring their gifts to you") — <em>shāy</em>: a gift, tribute (a rare word — Isa 18:7: "At that time tribute will be brought to the LORD of hosts"). The eschatological vision: the nations\' kings bringing their tribute to Jerusalem\'s temple — developed in Isa 60:3 and Rev 21:24-26.</p>',
    "30": '<p><strong>גְּעַר חַיַּת קָנֶה</strong> (<em>gĕʿar ḥayyat qāneh</em>, "Rebuke the beast that lurks in the reeds") — <em>gāʿar</em>: to rebuke (the authoritative command of the sovereign); <em>ḥayyat qāneh</em>: "the beast of the reeds" — likely the hippopotamus or crocodile (symbols of Egypt — cf. Ps 74:14: the Leviathan of Egypt; Ezek 29:3: the great dragon lying in the Nile). <strong>עֲדַת אַבִּירִים בְּעֶגְלֵי עַמִּים</strong> (<em>ʿădat ʾabbîrîm bĕʿeglê ʿammîm</em>, "the herd of bulls among the peoples\' young") — the foreign powers as bulls and calves: the strong nations surrounding weak ones. <strong>מִתְרַפֵּס בְּרַצֵּי-כָסֶף</strong> (<em>mitrappês bĕraṣṣê-khāsep</em>, "until they submit with pieces of silver") — <em>rāpas</em> (hithpael: to trample oneself down, to grovel, to prostrate): forced submission with tribute. <strong>בִּזַּר עַמִּים קְרָבוֹת יֶחְפָּצוּ</strong> (<em>bizzar ʿammîm qĕrābôt yeḥpāṣû</em>, "scatter the peoples who delight in war") — the divine rebuke scattering the war-delighting nations.</p>',
    "31": '<p><strong>יֶאֱתָיוּ חַשְׁמַנִּים מִנִּי מִצְרָיִם</strong> (<em>yeʾĕtāyû ḥashmannîm minnî miṣrāyim</em>, "Envoys will come from Egypt") — <em>ḥashmannîm</em>: dignitaries, princes, envoys (a rare word — possibly from an Egyptian loan-word; the nobles who make diplomatic submission). Egypt as the paradigm-oppressor making voluntary submission to God. <strong>כּוּשׁ תָּרִיץ יָדָיו לֵאלֹהִים</strong> (<em>kûsh tārîṣ yādāyw lêʾlōhîm</em>, "Ethiopia will quickly extend her hands to God") — <em>rûṣ</em> (hiphil: to cause to run, to stretch out quickly): Cush/Ethiopia extending hands in submission and worship. Isaiah 18:7 and 45:14 develop the same vision. The two great African powers of the ancient world submitting to Israel\'s God: the eschatological horizon of the psalm\'s processional.</p>',
    "32": '<p><strong>מַמְלְכוֹת הָאָרֶץ שִׁירוּ לֵאלֹהִים</strong> (<em>mamlaḵôt hāʾāreṣ shîrû lêʾlōhîm</em>, "Sing to God, O kingdoms of the earth") — the summons broadens to all kingdoms: not Israel alone but the <em>mamlaḵôt hāʾāreṣ</em>. The processional that began with the ark on Zion now encompasses the whole earth. <strong>זַמְּרוּ אֲדֹנָי סֶלָה</strong> (<em>zammĕrû ʾădōnāy selāh</em>, "sing praises to the Lord, Selah") — <em>zāmar</em>: to praise with instruments; <em>Selāh</em> marks the pause before the final doxological section.</p>',
    "33": '<p><strong>לָרֹכֵב בִּשְׁמֵי שְׁמֵי-קֶדֶם</strong> (<em>lārōkêb bishĕmê shĕmê-qedem</em>, "to him who rides upon the ancient heavens") — <em>shĕmê qedem</em>: "the heavens of old/antiquity" — the primordial heavens (Deut 33:27: "The eternal God is your dwelling place, and underneath are the everlasting arms"). The rider on the <em>ʿărābôt</em> (v4) is now the rider on the ancient heavens — both eternity (time) and the highest heavens (space) are under his sovereignty. <strong>הֵן יִתֵּן בְּקוֹלוֹ קוֹל עֹז</strong> (<em>hên yittên bĕqôlô qôl ʿōz</em>, "listen, he thunders with his mighty voice") — <em>qôl ʿōz</em>: the powerful voice (Ps 29:3-9 — the voice of the LORD over the waters, shattering cedars). The thunder as the divine speech addressed to all the earth.</p>',
    "34": '<p><strong>תְּנוּ עֹז לֵאלֹהִים</strong> (<em>tĕnû ʿōz lêʾlōhîm</em>, "Ascribe power to God") — <em>nātan ʿōz</em>: to "give" power — not that God receives power from human declaration, but that the assembly acknowledges and ascribes to God the power that is already his (Ps 29:1-2: "Ascribe to the LORD glory and strength"). <strong>עַל-יִשְׂרָאֵל גַּאֲוָתוֹ</strong> (<em>ʿal-yiśrāʾêl gaʾăwātô</em>, "his splendor is over Israel") — <em>gaʾăwāh</em>: majesty, splendor (the divine majesty — Exod 15:7: "In the greatness of your majesty you overthrow your adversaries"). God\'s majesty displayed specifically over Israel — the chosen people as the theater of divine splendor. <strong>וְעֻזּוֹ בַּשְּׁחָקִים</strong> (<em>wĕʿuzzô bashĕḥāqîm</em>, "and his strength is in the heavens") — <em>shĕḥāqîm</em>: the sky-dust, the clouds/heavens (from <em>shāḥaq</em>: to rub fine).</p>',
    "35": '<p><strong>נוֹרָא אֱלֹהִים מִמִּקְדָּשֶׁיךָ</strong> (<em>nôrāʾ ʾĕlōhîm mimmiqddāshêkā</em>, "God is awe-inspiring from his sanctuary") — <em>nôrāʾ</em>: fearful, awesome (as in Ps 65:5 — the God of awesome deeds). The processional psalm ends where it began — at the sanctuary, the place of God\'s dwelling. <strong>אֵל יִשְׂרָאֵל הוּא נֹתֵן עֹז וְתַעֲצֻמוֹת לָעָם</strong> (<em>ʾêl yiśrāʾêl hûʾ nōtên ʿōz wĕtaʿăṣumôt lāʿām</em>, "the God of Israel is the one who gives strength and power to the people") — <em>taʿăṣumôt</em>: mighty forces, powers (from <em>ʿāṣam</em>: to be strong — the abstract noun for concentrated power). The God asked to "show your strength" (v28) is revealed as the one who gives strength and power to those who worship. <strong>בָּרוּךְ אֱלֹהִים</strong> (<em>bārûk ʾĕlōhîm</em>, "Blessed be God") — the closing doxology bookending v19\'s "Blessed be the Lord."</p>',
  },
  "69": {
    "1": '<p>Psalm 69 is the second most cited individual psalm in the NT (after Ps 22), with at least eight distinct quotations or allusions. The opening is the urgent lament-cry. <strong>הוֹשִׁיעֵנִי אֱלֹהִים כִּי בָאוּ מַיִם עַד-נָפֶשׁ</strong> (<em>hôshîʿênî ʾĕlōhîm kî bāʾû mayim ʿad-nāpesh</em>, "Save me, O God, for the waters have come up to my soul/throat") — <em>hôshîʿa</em> (hiphil imperative: save! deliver!): the urgent cry naming the LORD as the only rescuer. <em>Bāʾû mayim ʿad-nāpesh</em>: "the waters have come to the <em>nāpesh</em>" — the <em>nāpesh</em> is both "soul" and "throat" (the life-breath in the throat): water up to the throat is the moment before drowning. The liturgical tune (<em>shôshannîm</em>: "to the tune of Lilies") frames this urgent lament within Israel\'s worship practice.</p>',
    "2": '<p><strong>טָבַעְתִּי בִּיוֹן מְצוּלָה</strong> (<em>ṭābaʿtî bîyôn mĕṣûlāh</em>, "I am sinking in the deep mud") — <em>ṭābaʿ</em>: to sink, to be submerged (as in Exod 15:4: Pharaoh\'s chariots "sank" in the Red Sea); <em>yāwen</em>: miry clay, swamp-mud (the sucking mud that holds the foot — also Ps 40:2 where God drew the Psalmist out of it). <em>Mĕṣûlāh</em>: the deep, the abyss. <strong>מַיִם עָמְקִים שִׁבֹּלֶת שְׁטָפַתְנִי</strong> (<em>mayim ʿāmĕqîm shibbolet shĕṭāpatni</em>, "the deep waters flood over me") — <em>shibbōlet</em>: a flowing stream, a flood-current (the same word as the "Shibboleth" test of Judg 12:6). The image: the Psalmist sinking in the swamp-mud while the flood-current sweeps over him — no ground underfoot and no escape above.</p>',
    "3": '<p><strong>יָגַעְתִּי בְקָרְאִי נִחַר גְּרוֹנִי</strong> (<em>yāgaʿtî bĕqārʾî niḥar gĕrônî</em>, "I am exhausted from calling out; my throat is raw") — <em>yāgaʿ</em>: to be weary, to be worn out; <em>nāḥar</em>: to be raw, to be parched (the scorched, burned-out throat from continuous crying). <strong>כָּלוּ עֵינַי מְיַחֵל לֵאלֹהָי</strong> (<em>kālû ʿênay mĕyaḥêl lêʾlōhāy</em>, "my eyes have given out while waiting for my God") — <em>kālāh</em>: to be consumed, to fail (the eyes that have scanned the horizon for God\'s arrival until they are burned out — Ps 119:82: "my eyes fail from searching your promise"). <em>Mĕyaḥêl</em> (piel participle: waiting with hope — from <em>yāḥal</em>: to wait in hope): the exhaustion comes not from despair but from sustained, hoping expectation. Voice and eyes are both spent, yet the waiting continues.</p>',
    "4": '<p><strong>רַבּוּ מִשַּׂעֲרוֹת רֹאשִׁי שֹׂנְאַי חִנָּם</strong> (<em>rabbû miśśaʿărôt rōʾshî śōnĕʾay ḥinnām</em>, "Those who hate me without cause outnumber the hairs of my head") — <em>ḥinnām</em>: without cause, for nothing, gratuitously. John 15:25 quotes this word directly: "They hated me without a cause" — Jesus applies this verse to himself, identifying himself as the righteous sufferer of Ps 69. <strong>אֲשֶׁר לֹא-גָזַלְתִּי אָז אָשִׁיב</strong> (<em>ʾăsher lōʾ-gāzaltî ʾāz ʾāshîb</em>, "what I did not steal, I must now restore") — a forensic expression: being compelled to pay back (<em>shûb</em>: to return, to restore) what one did not take (<em>gāzal</em>: to rob). The Psalmist bears the punishment for wrongs he did not commit. The NT applies this to Christ\'s substitutionary suffering: bearing the debt of sins not his own.</p>',
    "5": '<p><strong>אֱלֹהִים אַתָּה יָדַעְתָּ לְאִוַּלְתִּי</strong> (<em>ʾĕlōhîm ʾattāh yādaʿtā lĕʾiwwaltî</em>, "O God, you know my foolishness") — <em>ʾiwwelet</em>: folly (the moral recklessness — from <em>ʾĕwîl</em>: the fool). The Psalmist makes no claim to innocence before God: the "without cause" hatred of v4 exists even though the Psalmist has genuinely sinned. <strong>וְאַשְׁמוֹתַי מִמְּךָ לֹא-נִכְחָדוּ</strong> (<em>wĕʾashmôtay mimmĕkā lōʾ-niḵḥādû</em>, "and my sins are not concealed from you") — <em>ʾashmāh</em>: guilt, offense; <em>kāḥad</em> (niphal: to be concealed). The transparency before God — the Psalmist knows that his own guilt is visible to the judge even as he protests that the enemy\'s hatred is groundless. Both are simultaneously true.</p>',
    "6": '<p><strong>אַל-יֵבֹשׁוּ בִי קֹוֶיךָ אֲדֹנָי יְהוִה צְבָאוֹת</strong> (<em>ʾal-yēbōshû bî qōwêkā ʾădōnāy yĕhwāh ṣĕbāʾôt</em>, "Let not those who hope in you be disgraced because of me, O Lord GOD of hosts") — the Psalmist\'s concern is not merely for himself but for those who share his trust in God: his public failure would publicly discredit all who trust the same God. <em>Qāwāh</em>: to hope, to wait with expectation. The full threefold divine name (Lord YHWH of hosts) is the highest possible divine authority. <strong>אַל-יִכָּלְמוּ בִי מְבַקְשֶׁיךָ אֱלֹהֵי יִשְׂרָאֵל</strong> (<em>ʾal-yikkālĕmû bî mĕbaqshêkā ʾĕlōhê yiśrāʾêl</em>) — <em>kālam</em>: to be put to shame publicly (as opposed to <em>bôsh</em> — <em>kālam</em> has the nuance of being made to look foolish before others). The seekers of God would be publicly humiliated if the psalmist\'s suffering were read as divine abandonment.</p>',
    "7": '<p><strong>כִּי-עָלֶיךָ נָשָׂאתִי חֶרְפָּה</strong> (<em>kî-ʿālêkā nāśāʾtî ḥerpāh</em>, "For your sake I have borne disgrace") — <em>nāśāʾ</em>: to carry, to bear (the load-bearing verb — Isa 53:4 uses the same verb: the Servant "bore our griefs"). <em>Ḥerpāh</em>: reproach, disgrace, the public shame of the accused. The motivation: the disgrace is borne "for your sake" (<em>ʿālêkā</em>) — the suffering is vicarious in character; it comes because of the Psalmist\'s identification with God. <strong>כִּסְּתָה כְלִמָּה פָּנָי</strong> (<em>kissĕtāh kĕlimmāh pānāy</em>, "humiliation has covered my face") — the face — the seat of personal honor in ancient Near Eastern culture — covered/buried under humiliation.</p>',
    "8": '<p><strong>מוּזָר הָיִיתִי לְאֶחָי</strong> (<em>mûzār hāyîtî lĕʾeḥāy</em>, "I have become a stranger to my brothers") — <em>zār</em>: a stranger, a foreigner (one who is not at home). The estrangement from one\'s own family as a result of identification with God is the deepest social wound: the covenant community that should be the place of belonging becomes the place of alienation. <strong>וְנָכְרִי לִבְנֵי אִמִּי</strong> (<em>wĕnokrî libnê ʾimmî</em>, "an outsider to my own mother\'s children") — <em>nokrî</em>: the foreign one, the one not of the household (a stronger term than <em>zār</em>). John 7:5 notes that Jesus\'s brothers did not believe in him — the NT applies this estrangement directly to Christ.</p>',
    "9": '<p><strong>כִּי-קִנְאַת בֵּיתְךָ אֲכָלָתְנִי</strong> (<em>kî-qinʾat bêtĕkā ʾăkālatni</em>, "Zeal for your house has consumed me") — <em>qinʾāh</em>: zeal, jealousy (the passionate, exclusive devotion — as in Num 25:11 where Phinehas\'s "zeal" turned back God\'s wrath). <em>ʾĀkal</em>: to eat, to consume (the fire-like consuming of zeal — Exod 24:17: "the LORD appeared... like a consuming fire"). John 2:17 quotes this verse when Jesus cleanses the temple: "His disciples remembered that it was written, \'Zeal for your house will consume me.\'" The switch from aorist ("has consumed") to future ("will consume") in John reflects the eschatological intensification — the temple action is the beginning of a consuming that ends at the cross. <strong>וְחֶרְפּוֹת חוֹרְפֶיךָ נָפְלוּ עָלָי</strong> (<em>wĕḥerpôt ḥôrpêkā nāplû ʿālay</em>, "and the insults directed at you have landed on me") — Rom 15:3 applies this to Christ: "the reproaches of those who reproached you fell upon me."</p>',
    "10": '<p><strong>וָאֶבְכֶּה בַצּוֹם נַפְשִׁי</strong> (<em>wāʾebkeh baṣṣôm napshî</em>, "When I wept and humbled my soul with fasting") — <em>bākāh</em>: to weep; <em>ṣôm</em>: fasting (the self-humbling discipline — Joel 2:12); <em>ʿinnāh nāpesh</em>: to humble/afflict the soul (the technical language of the Day of Atonement — Lev 16:31; 23:27). <strong>וַתְּהִי לַחֲרָפוֹת לִי</strong> (<em>wattĕhî laḥărāpôt lî</em>, "that became a source of shame for me") — the reversal: the acts of piety (weeping, fasting) that should have won social sympathy instead became the material for reproach. The righteous disciplines made the Psalmist a spectacle.</p>',
    "11": '<p><strong>וָאֶתְּנָה לְבוּשִׁי שָׂק</strong> (<em>wāʾetĕnāh lĕbûshî śāq</em>, "I dressed in sackcloth") — <em>śaq</em>: sackcloth, the coarse garment of mourning and penitence (2 Sam 3:31; Isa 37:1). The sackcloth signals the Psalmist\'s internal state to the community — the visible mourning garment worn as a communal communication of grief. <strong>וָאֱהִי לָהֶם לְמָשָׁל</strong> (<em>wāʾĕhî lāhem lĕmāshāl</em>, "and I became a laughingstock to them") — <em>māshāl</em>: a proverb, a byword (as in Deut 28:37; 1 Kgs 9:7 — becoming a "byword" means becoming the negative illustration everyone cites). The mourner mocked: the sackcloth meant to elicit sympathy confirms in the observers\' minds that the Psalmist is a lost cause.</p>',
    "12": '<p><strong>יָשִׂיחוּ בִי יֹשְׁבֵי שָׁעַר</strong> (<em>yāśîḥû bî yōshĕbê shāʿar</em>, "Those who sit at the city gate gossip about me") — <em>yāśaḥ</em>: to speak, to meditate aloud; <em>yōshĕbê shāʿar</em>: "those who sit at the gate" — the civic and judicial center of ancient cities (Ruth 4:1-11; Prov 31:23). The very place where legal proceedings happen — the seat of official life — has become the place where the Psalmist is discussed as a public scandal. <strong>וּנְגִינוֹת שׁוֹתֵי שֵׁכָר</strong> (<em>ûnĕgînôt shôtê shêkār</em>, "and I have become the subject of the drunkards\' songs") — <em>nĕgînāh</em>: a song, a musical piece. From the city gate\'s judiciary to the tavern\'s drunkards, the whole social spectrum has made him the object of derision.</p>',
    "13": '<p><strong>וַאֲנִי תְפִלָּתִי-לְךָ יְהוָה</strong> (<em>waʾănî tĕpillātî-lĕkā yĕhwāh</em>, "But as for me, my prayer is directed to you, LORD") — the contrastive <em>waʾănî</em> (but I, as for me): despite the universal mockery (vv11-12), the Psalmist\'s orientation remains fixed on YHWH alone. <strong>עֵת רָצוֹן אֱלֹהִים</strong> (<em>ʿêt rāṣôn ʾĕlōhîm</em>, "at a time of your favor, O God") — <em>ʿêt rāṣôn</em>: the acceptable/favorable time (Isa 49:8: "In the time of favor I have answered you" — Paul cites Isa 49:8 in 2 Cor 6:2: "Now is the acceptable time"). <strong>בְּרָב-חַסְדְּךָ עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ</strong> (<em>bĕrāb-ḥasdĕkā ʿănênî beʾĕmet yishʿekā</em>, "O God, in your great steadfast love, answer me in the truth of your salvation") — the twin grounds of appeal: the vastness of divine <em>ḥesed</em> (as in Ps 51:1) and the faithfulness (<em>ʾemet</em>) of divine salvation. The covenant-reliability that makes God\'s salvation trustworthy, not merely possible.</p>',
    "14": '<p><strong>הַצִּילֵנִי מִטִּיט וְאַל-אֶטְבָּעָה</strong> (<em>haṣṣîlênî miṭṭîṭ wĕʾal-ʾeṭbāʿāh</em>, "Rescue me from the mire and do not let me sink") — <em>ṭîṭ</em>: mud, mire (the same swamp-mud of v2); <em>ṭābaʿ</em> (now negated in petition): the opening image is petitioned against — what I am sinking in, rescue me from. <strong>אִנָּצְלָה מִשֹּׂנְאַי</strong> (<em>ʾinnāṣĕlāh miśśōnĕʾay</em>, "let me be saved from those who hate me") — <em>nāṣal</em> (niphal: to be rescued — the passive petition when the Psalmist cannot rescue himself). <strong>וּמִמַּעֲמַקֵּי-מָיִם</strong> (<em>ûmimmaʿămaqqê-māyim</em>, "and from the deep waters") — <em>maʿămaqqîm</em>: depths (as in Ps 130:1: "Out of the depths I cry to you, LORD"). The petition covers both the swamp below (mire) and the flood above (deep waters).</p>',
    "15": '<p><strong>אַל-תִּשְׁטְפֵנִי שִׁבֹּלֶת מַיִם</strong> (<em>ʾal-tishṭĕpênî shibbolet mayim</em>, "Let not the flood sweep me away") — <em>shāṭap</em>: to flood over, to sweep away; <em>shibbōlet</em>: the stream-current (as in v2). <strong>וְאַל-תִּבְלָעֵנִי מְצוּלָה</strong> (<em>wĕʾal-tiblāʿênî mĕṣûlāh</em>, "let not the depths swallow me") — <em>bālaʿ</em>: to swallow, to engulf (as in Num 16:30-32: the earth "swallowed" Korah). <strong>וְאַל-תֶּאְטַר-עָלַי בְּאֵר פִּיהָ</strong> (<em>wĕʾal-teʾṭar-ʿālay bĕʾêr pîhā</em>, "let not the pit close its mouth on me") — <em>ʾāṭar</em>: to close (the shutting of the pit\'s mouth above the one thrown in — Gen 37:24: Joseph thrown into the pit). Three petitions covering the three dangers: flood, depth, and the closure of Sheol.</p>',
    "16": '<p><strong>עֲנֵנִי יְהוָה כִּי-טוֹב חַסְדֶּךָ</strong> (<em>ʿănênî yĕhwāh kî-ṭôb ḥasdekā</em>, "Hear me, LORD, for your steadfast love is good") — the ground of appeal: the goodness of divine <em>ḥesed</em>. <em>Ṭôb ḥesed</em>: "good steadfast love" — the goodness is both a quality of the love and a statement about the character of a God whose love exceeds rather than just meets obligation (compare Ps 63:3: "<em>ḥesed</em> is better than life"). <strong>כְּרֹב רַחֲמֶיךָ פְּנֵה אֵלָי</strong> (<em>kĕrōb raḥămêkā pĕnêh ʾêlay</em>, "in your great compassion, turn toward me") — <em>raḥămîm</em>: the plural of deep compassion (from <em>reḥem</em>: the womb — the maternal tenderness; Isa 49:15). The plural intensifies: not a single act of compassion but the full reservoir of divine motherly tenderness turned toward the drowning petitioner.</p>',
    "17": '<p><strong>וְאַל-תַּסְתֵּר פָּנֶיךָ מֵעַבְדֶּךָ</strong> (<em>wĕʾal-tastêr pānêkā mêʿabdekā</em>, "Do not turn your face away from your servant") — <em>sātar pānîm</em>: "to hide the face" (the technical term for divine withdrawal — Ps 13:1; 27:9; 44:24 — the experience of divine absence). <strong>כִּי-צַר-לִי מַהֵר עֲנֵנִי</strong> (<em>kî-ṣar-lî mahêr ʿănênî</em>, "I am in great distress — answer me quickly") — <em>ṣar</em>: the narrow/tight place, the anguish of having no room. <em>Mahêr</em>: quickly (the adverb of urgency — not that God\'s timing is wrong but that the situation is desperate). The "quickly" of the drowning person to the rescuer: not a demand but a description of extremity.</p>',
    "18": '<p><strong>קָרְבָה אֶל-נַפְשִׁי גְאָלָהּ</strong> (<em>qorbāh ʾel-napshî gĕʾālāh</em>, "Come near to my soul and rescue it") — <em>qārab</em>: to draw near; <em>gāʾal</em>: to redeem, to act as the <em>gōʾêl</em> (the kinsman-redeemer who restores the lost family member — Ruth 4:4-6; Lev 25:25). God petitioned to come near and exercise kinsman-redemption on the drowning soul. <strong>לְמַעַן אֹיְבַי פְּדֵנִי</strong> (<em>lĕmaʿan ʾôyĕbay pĕdênî</em>, "set me free because of my enemies") — <em>pādāh</em>: to ransom, to redeem by payment. The "because of" (<em>lĕmaʿan</em>) is remarkable: the enemies\' existence is itself the argument for rescue — God\'s character is vindicated when the righteous sufferer is rescued from those who wrongly persecute him.</p>',
    "19": '<p><strong>אַתָּה יָדַעְתָּ חֶרְפָּתִי וּבָשְׁתִּי וּכְלִמָּתִי</strong> (<em>ʾattāh yādaʿtā ḥerpātî ûbāshtî ûkĕlimmātî</em>, "You know my disgrace, my shame, and my humiliation") — three terms for public dishonor accumulating: <em>ḥerpāh</em> (disgrace/reproach — v9), <em>bōshet</em> (shame — the state of being put to shame), <em>kĕlimmāh</em> (humiliation — the being-made-to-look-foolish of v6). God knows all three dimensions of the Psalmist\'s public destruction. <strong>נֶגְדְּךָ כָּל-צוֹרְרָי</strong> (<em>negdĕkā kol-ṣôrĕrāy</em>, "all my enemies are in your sight") — <em>neged</em>: before, in plain sight of. The appeal: if God sees it all, let him act on what he sees.</p>',
    "20": '<p><strong>חֶרְפָּה שָׁבְרָה לִבִּי</strong> (<em>ḥerpāh shābrāh libbî</em>, "Disgrace has broken my heart") — <em>shābar</em>: to break, to shatter (as in Ps 34:18: "The LORD is near to the brokenhearted" — <em>nishbĕrê lêb</em>). The reproach (<em>ḥerpāh</em>) as the breaking-agent for the heart: the sustained public dishonor has shattered the inner center. <strong>וָאֲנוּשָׁה</strong> (<em>wāʾănûshāh</em>, "and I am in anguish") — <em>ʾānash</em>: to be mortally ill, to be beyond recovery (Jer 17:9: "the heart is <em>ʾānûsh</em> — desperately sick"; Jer 30:12: a wound that is incurable). <strong>וָאֲקַוֶּה לָנוּד וָאַיִן</strong> (<em>wāʾăqawweh lānûd wāʾayin</em>, "I looked for someone to show compassion, but there was none") — <em>nûd</em>: to nod in sympathy, to show compassion (Job 2:11: "they went to comfort and console him"). <em>Wayyāyin</em>: and there was none — the absolute absence of any human comforter. The isolation is complete.</p>',
    "21": '<p>The most cited verse of Psalm 69 in the Passion narratives. <strong>וַיִּתְּנוּ בְּבָרוּתִי רֹאשׁ</strong> (<em>wayyittĕnû bĕbārûtî rōʾsh</em>, "They put bitter gall in my food") — <em>bārût</em>: food, bread (the sustaining meal); <em>rōʾsh</em>: gall, head-poison (a bitter, poisonous plant — Amos 6:12: "wormwood"). They put poison in what was meant to sustain. <strong>וְלִצְמָאִי יַשְׁקוּנִי חֹמֶץ</strong> (<em>wĕliṣmāʾî yashqûnî ḥōmeṣ</em>, "and when I was thirsty, they offered me vinegar to drink") — <em>ḥōmeṣ</em>: vinegar, sour wine (acidic, undrinkable as a refreshment). Matt 27:34 (gall mixed with wine given to Jesus before crucifixion) and Matt 27:48/John 19:29 (vinegar on a sponge at the cross) fulfill this verse. John 19:28 explicitly notes that Jesus said "I thirst" "so that the scripture would be fulfilled" — a direct citation of this verse\'s thirst-and-vinegar scene.</p>',
    "22": '<p><strong>יְהִי-שֻׁלְחָנָם לִפְנֵיהֶם לְפָח</strong> (<em>yĕhî-shulḥānām lipnêhem lĕpāḥ</em>, "Let their table be set as a snare before them") — <em>shulḥān</em>: a table (the meal, the place of fellowship and covenant); <em>pāḥ</em>: a bird-trap, a snare. The table — the symbol of hospitality and covenant fellowship — becomes a trap. <strong>וְלִשְׁלוֹמִים לְמוֹקֵשׁ</strong> (<em>wĕlishlômîm lĕmôqêsh</em>, "and what was meant for their prosperity become a trap") — <em>shālôm</em> (plural: prosperity, peace); <em>môqêsh</em>: a snare (Ps 64:5). Romans 11:9-10 quotes vv22-23 directly, applying them to Israel\'s hardening: their table (Torah, temple, covenant privilege) has become a trap through rejection of the Messiah. Paul\'s application is the ultimate reversal: what was given for salvation has been used for stumbling.</p>',
    "23": '<p><strong>תֶּחְשַׁכְנָה עֵינֵיהֶם מֵרְאוֹת</strong> (<em>teḥshaknahnāh ʿênêhem mêrĕʾôt</em>, "Let their eyes be darkened so they cannot see") — <em>ḥāshak</em>: to be dark, to grow dark (Ps 18:28: "you lighten my darkness"; Isa 5:30: "the light is dark in the clouds"). The darkened eyes of those who refused to see now unable to see at all: the judicial punishment fitting the sin of willful blindness. Romans 11:10 quotes: "Let their eyes be darkened so that they cannot see." <strong>וּמָתְנֵיהֶם תָּמִיד הַמְעַד</strong> (<em>ûmātnêhem tāmîd hamʿad</em>, "and let their bodies tremble without ceasing") — <em>mātên</em>: the loins/hips (the center of physical strength); <em>maʿad</em> (hiphil: to cause to shake): the shaking of the loins as physical strength fails. Double judgment: vision darkened, physical strength failing — the complete debility of those from whom God withdraws.</p>',
    "24": '<p><strong>שְׁפָךְ-עֲלֵיהֶם זַעְמֶךָ</strong> (<em>shĕpōk-ʿălêhem zaʿmekā</em>, "Pour out your wrath upon them") — <em>shāpak zaʿam</em>: the pouring out of divine wrath (Jer 10:25: "Pour out your wrath on the nations"; Rev 16: the seven bowls of wrath poured out). <em>Zaʿam</em>: wrath, indignation (the burning anger that scorches what it falls on — distinct from <em>ʾap</em>: the flaring nostril-anger). <strong>וַחֲרוֹן אַפְּךָ יַשִּׂיגֵם</strong> (<em>waḥărôn ʾappĕkā yaśśîgêm</em>, "let your fierce anger seize them") — <em>ḥărôn ʾap</em>: the burning of the nostrils (Exod 32:12); <em>nāśag</em> (hiphil: to overtake, to catch up with — as a pursuing force catches the fleeing). The imprecatory petition: the enemies\' actions warrant the judgment now called down upon them.</p>',
    "25": '<p><strong>תְּהִי-טִירָתָם נְשַׁמָּה</strong> (<em>tĕhî-ṭîrātām nĕshammāh</em>, "Let their camp become desolate") — <em>ṭîrāh</em>: encampment, fortified settlement; <em>shāmam</em> (niphal: to be desolate, to be devastated). <strong>בְּאָהֳלֵיהֶם אַל-יְהִי יֹשֵׁב</strong> (<em>bĕʾōhŏlêhem ʾal-yĕhî yōshêb</em>, "let no one live in their dwelling") — the total emptying of the dwellings. Acts 1:20 quotes this verse directly with reference to Judas Iscariot: "For it is written in the Book of Psalms, \'Let his homestead become desolate, and let there be no one to live in it.\'" Peter applies the judicial prayer of the persecuted righteous to the specific betrayer of Jesus, identifying Judas as the embodiment of the enemies of the anointed sufferer.</p>',
    "26": '<p><strong>כִּי-אַתָּה אֲשֶׁר-הִכִּיתָ רָדָפוּ</strong> (<em>kî-ʾattāh ʾăsher-hikkîtā rādāpû</em>, "For they have harassed the one whom you have afflicted") — <em>nākāh</em> (hiphil: to strike, to smite): God himself has struck the Psalmist (permitted or caused the affliction — Isa 53:4: "we esteemed him stricken, smitten by God"). The enemies pile on the one already struck by God — the double wound of divine affliction and human persecution. <strong>וְאֶל-מַכְאוֹב חֲלָלֶיךָ יְסַפֵּרוּ</strong> (<em>wĕʾel-makʾôb ḥălālêkā yĕsappêrû</em>, "and they gossip about the suffering of those you have wounded") — <em>makʾôb</em>: pain, anguish (from <em>kāʾab</em>: to be pained — Isa 53:3-4: the Servant who was "a man of sorrows"). The mockers take the divine wounding as the occasion for gossip rather than compassion.</p>',
    "27": '<p><strong>תְּנָה-עָוֹן עַל-עֲוֹנָם</strong> (<em>tĕnāh-ʿāwōn ʿal-ʿăwōnām</em>, "Pile their guilt on top of their guilt") — the imprecatory petition: <em>nātan ʿāwōn ʿal ʿāwōn</em>: "give iniquity upon their iniquity" — the judicial principle of compounding guilt for compounded sin. They who persecuted the afflicted one have added offense upon offense; let the accounting reflect the accumulation. <strong>וְאַל-יָבֹאוּ בְּצִדְקָתֶךָ</strong> (<em>wĕʾal-yābōʾû bĕṣidqātekā</em>, "and do not let them share in your vindication") — <em>ṣĕdāqāh</em>: righteousness, vindication (the divine declaration of right — Isa 46:13). Let them have no share in the acquittal that the righteous sufferer receives.</p>',
    "28": '<p><strong>יִמָּחוּ מִסֵּפֶר חַיִּים</strong> (<em>yimmāḥû missêper ḥayyîm</em>, "Let them be erased from the scroll of the living") — <em>māḥāh</em> (niphal: to be wiped out, to be erased — Exod 32:32-33 where Moses asks to be "blotted out" of God\'s book). <em>Sêper ḥayyîm</em>: "the scroll of the living" — the divine register of the living (Exod 32:32; Isa 4:3; Luke 10:20). Revelation 3:5 echoes this verse in the reverse: "I will not blot out his name from the book of life." <strong>וְעִם-צַדִּיקִים אַל-יִכָּתֵבוּ</strong> (<em>wĕʿim-ṣaddîqîm ʾal-yikkātêbû</em>, "let them not be listed among the righteous") — exclusion from both registers: the scroll of life and the company of the righteous. The two registers are related: to be in the book of life is to be among the righteous; exclusion is double.</p>',
    "29": '<p><strong>וַאֲנִי עָנִי וְכֹאֵב</strong> (<em>waʾănî ʿānî wĕkōʾêb</em>, "But I am afflicted and in pain") — the contrastive return to the individual sufferer after the imprecatory section: the enemies in their guilt; the Psalmist in his affliction and pain. <em>ʿĀnî</em>: afflicted, lowly; <em>kōʾêb</em>: in pain (from <em>kāʾab</em>: the same word as the Servant\'s "sorrows" in Isa 53). <strong>יְשׁוּעָתְךָ אֱלֹהִים תְּשַׂגְּבֵנִי</strong> (<em>yĕshûʿātĕkā ʾĕlōhîm tĕśaggĕbênî</em>, "may your salvation, O God, lift me up") — <em>śāgab</em> (piel: to set on high, to lift to safety — Ps 59:1; 91:14). The salvation lifts the lowly to a high secure place — the rescue from the mire of vv2-3 accomplished.</p>',
    "30": '<p><strong>אֲהַלְלָה שֵׁם-אֱלֹהִים בְּשִׁיר</strong> (<em>ʾăhallĕlāh shêm-ʾĕlōhîm bĕshîr</em>, "I will praise the name of God with a song of praise") — the psalm pivots from lament and imprecation to vow and praise: the personal testimony of the rescued sufferer (as in Ps 22:22: "I will tell of your name to my brothers"). <em>Hālal</em> (piel: to praise lavishly — the root of <em>hallĕlû-Yāh</em>). <strong>וַאֲגַדְּלֶנּוּ בְתוֹדָה</strong> (<em>waʾăgaddĕlennû bĕtôdāh</em>, "I will honor him with thanksgiving") — <em>gādal</em> (piel: to make great, to magnify); <em>tôdāh</em>: the thanksgiving offering (Ps 50:23: "The one who offers the sacrifice of thanksgiving glorifies me"). The magnifying of God is the Psalmist\'s act of making God\'s greatness visible and audible to others.</p>',
    "31": '<p><strong>וְתִיטַב לַיהוָה מִשּׁוֹר פָּר</strong> (<em>wĕtîṭab laYHWH mishôr par</em>, "This will please the LORD more than an ox or a bull") — <em>yāṭab</em> (qal: to be good, to be pleasing): the praise-song will please God more than the largest and most expensive animal sacrifices. <strong>מַקְרִן מַפְרִיס</strong> (<em>maqrîn maphrîs</em>, "with its horns and hoofs") — <em>qeren</em>: horn (the sign of mature strength and full value in a sacrificial animal); <em>pāras</em>: hoof (split hoof — the clean-animal marker of Lev 11:3). The most valuable possible sacrifice: a mature bull with full horns and clean hoofs. The Psalmist claims that heartfelt praise and thanksgiving exceed this. Ps 50:14 and 51:17 develop the same tradition: "The sacrifice acceptable to God is a broken spirit."</p>',
    "32": '<p><strong>רָאוּ עֲנָוִים יִשְׂמָחוּ</strong> (<em>rāʾû ʿănāwîm yiśmāḥû</em>, "The afflicted will see it and rejoice") — <em>ʿānāw</em>: the humble, the meek, the afflicted (the same social class as the Psalmist — those who have no earthly recourse). When they see the Psalmist\'s rescue, they rejoice: the personal testimony of salvation is the communal encouragement of all who suffer similarly. <strong>דֹּרְשֵׁי אֱלֹהִים וִיחִי לְבַבְכֶם</strong> (<em>dōrshê ʾĕlōhîm wîḥî lĕbabkem</em>, "those of you who seek God, may your hearts be renewed") — <em>dārash</em>: to seek diligently (Ps 34:4; Amos 5:4: "seek me and live"); <em>ḥāyāh</em> (qal: may your hearts live) — the living of the heart as the opposite of the broken heart (v20). The assembly encouraged by one rescued person\'s testimony.</p>',
    "33": '<p><strong>כִּי-שֹׁמֵעַ אֶל-אֶבְיוֹנִים יְהוָה</strong> (<em>kî-shōmêaʿ ʾel-ʾebyônîm yĕhwāh</em>, "For the LORD listens to the needy") — <em>ʾebyôn</em>: the needy, the destitute (from <em>ʾābāh</em>: to desire, to want — the one in want). YHWH hears specifically what no human hears — the cry of the poorest. <strong>וְאֶת-אֲסִירָיו לֹא בָזָה</strong> (<em>wĕʾet-ʾăsîrāyw lōʾ bāzāh</em>, "he does not look down on those he has bound") — <em>ʾāsar</em>: to bind (his prisoners, his bound ones — those whose affliction comes as if they were prisoners in God\'s custody); <em>bāzāh</em>: to despise. God does not despise the very ones he has allowed to suffer: their suffering is not evidence of divine contempt but of divine pedagogy. Ps 22:24 expresses the same truth: "he has not despised or scorned the suffering of the afflicted one."</p>',
    "34": '<p><strong>יְהַלְלוּהוּ שָׁמַיִם וָאָרֶץ</strong> (<em>yĕhallĕlûhû shāmayim wāʾāreṣ</em>, "Let heaven and earth give him praise") — the cosmic praise (as in Ps 148 — the entire creation summoned). <strong>יַמִּים וְכָל-רֹמֵשׂ בָּם</strong> (<em>yammîm wĕkol-rōmêś bām</em>, "the seas and every living thing in them") — <em>rōmêś</em>: everything that creeps/moves (Gen 1:21-26). The scope: heaven, earth, and sea — the three zones of creation all summoned to praise the God who hears the needy. The personal lament psalm broadens at its close to cosmic dimensions: the individual\'s rescue is an event of universal significance.</p>',
    "35": '<p><strong>כִּי אֱלֹהִים יוֹשִׁיעַ צִיּוֹן</strong> (<em>kî ʾĕlōhîm yôshîaʿ ṣiyyôn</em>, "For God will save Zion") — the eschatological horizon: the individual\'s rescue (v29) is a sample of Zion\'s rescue. <em>Yôshîaʿ</em> (hiphil imperfect: will save — the future certainty based on the divine character). <strong>וְיִבְנֶה עָרֵי יְהוּדָה</strong> (<em>wĕyibneh ʿārê yĕhûdāh</em>, "and rebuild the cities of Judah") — the rebuilding of destroyed cities (Isa 54:3; 61:4). <strong>וְיָשְׁבוּ שָׁם וִירֵשׁוּהָ</strong> (<em>wĕyāshĕbû shām wîrêshûhā</em>, "people will live there and take possession of it") — the restoration of the covenant people to their land as the conclusive sign of divine salvation.</p>',
    "36": '<p><strong>וְזֶרַע עֲבָדָיו יִנְחָלוּהָ</strong> (<em>wĕzeraʿ ʿăbādāyw yinḥālûhā</em>, "The children of his servants will inherit it") — <em>zeraʿ</em>: seed, offspring (the covenant continuity through generations — Gen 17:7-8: "your seed after you"); <em>nāḥal</em>: to inherit (the covenantal transfer of the land from generation to generation). <strong>וְאֹהֲבֵי שְׁמוֹ יִשְׁכְּנוּ-בָהּ</strong> (<em>wĕʾōhăbê shĕmô yishkĕnû-bāh</em>, "and those who love his name will live there") — the defining characteristic of the inheritors: not ethnic descent alone but love of the divine name (Ps 5:11: "let all who love your name rejoice in you"). The psalm that began in drowning waters ends with the seed of servants dwelling securely in an inherited land — the complete reversal of the lament\'s situation.</p>',
  },
  "70": {
    "1": '<p>Psalm 70 is virtually identical to Ps 40:13-17, condensed into a standalone emergency petition. The superscription adds <strong>לְהַזְכִּיר</strong> (<em>lĕhazzkîr</em>, "to bring to remembrance") — the <em>hiphil</em> infinitive of <em>zākar</em>: to remember. This marks it as a liturgical piece for "bringing [the worshiper\'s situation] to remembrance" before God (as in the <em>ʾazkārāh</em>, the memorial portion of the grain offering — Lev 2:2). The superscription frames the whole psalm as an act of presenting an urgent case to the divine court. The compression relative to Ps 40:13-17 (where the parallel passage follows extended thanksgiving) signals a standalone emergency use: extracted from its longer context and deployed as an urgent cry on its own. <strong>אֱלֹהִים לְהַצִּילֵנִי יְהוָה לְעֶזְרָתִי חוּשָׁה</strong> (<em>ʾĕlōhîm lĕhaṣṣîlênî yĕhwāh lĕʿezrātî ḥûshāh</em>, "O God, hurry to deliver me! O LORD, hurry to help me!") — two divine names paired with the single urgent command <em>ḥûshāh</em> (hurry! from <em>ḥûsh</em>: to hasten, to move quickly): the cry for speed from the one who cannot wait.</p>',
    "2": '<p><strong>יֵבֹשׁוּ וְיַחְפְּרוּ מְבַקְשֵׁי נַפְשִׁי</strong> (<em>yēbōshû wĕyaḥpĕrû mĕbaqshê napshî</em>, "Let those who seek my life be put to shame and confusion") — <em>bôsh</em>: to be put to shame; <em>ḥāpar</em>: to be confounded, to be humiliated (to dig or scratch the ground in embarrassment — the image of the defeated person unable to meet anyone\'s gaze). <strong>יִסֹּגוּ אָחוֹר וְיִכָּלְמוּ חֲפֵצֵי רָעָתִי</strong> (<em>yissōgû ʾāḥôr wĕyikkālĕmû ḥăpêṣê rāʿātî</em>, "let those who delight in my harm be turned back and put to disgrace") — <em>sûg</em>: to turn back, to withdraw, to be made to retreat (Isa 42:17: they "shall be turned back in utter shame"); <em>kālam</em>: the public humiliation (Ps 69:6-7). Three words for defeat in sequence: shame (<em>bôsh</em>), confusion (<em>ḥāpar</em>), public disgrace (<em>kālam</em>). The enemies\' three-fold humiliation mirrors the Psalmist\'s three-fold dishonor of Ps 69:19.</p>',
    "3": '<p><strong>יָשׁוּבוּ עַל-עֵקֶב בָּשְׁתָּם</strong> (<em>yāshûbû ʿal-ʿêqeb bāshtām</em>, "Let them be turned back in their shame") — <em>shûb ʿal-ʿêqeb</em>: "to be turned back on the heel" — the reversal of the direction of march (the army that advanced is turned backward on its own heels). <strong>הָאֹמְרִים הֶאָח הֶאָח</strong> (<em>hāʾōmĕrîm heʾāḥ heʾāḥ</em>, "those who say, \'Aha! Aha!\'") — the mocking exclamation <em>heʾāḥ</em> (as in Ps 35:21: "Aha! Aha! Our eyes have seen it!"; Ezek 26:2: "Aha, the gate of the peoples is broken"). The repeated exclamation captures the gloating of spectators at the Psalmist\'s downfall. The very exclamation that expressed their delight becomes the occasion of their own reversal.</p>',
    "4": '<p><strong>יָשִׂישׂוּ וְיִשְׂמְחוּ בְּךָ כָּל-מְבַקְשֶׁיךָ</strong> (<em>yāśîśû wĕyiśmĕḥû bĕkā kol-mĕbaqshêkā</em>, "But let all who seek you rejoice and be glad in you") — the contrast: while the enemies are turned back in shame, those who seek God are turned forward in joy. <em>Śîś</em> and <em>śāmaḥ</em>: the two joy verbs of Ps 68:3 — accumulated delight. <strong>וְיֹאמְרוּ תָמִיד יִגְדַּל אֱלֹהִים אֹהֲבֵי יְשׁוּעָתֶךָ</strong> (<em>wĕyōʾmĕrû tāmîd yigdal ʾĕlōhîm ʾōhăbê yĕshûʿātekā</em>, "let those who love your salvation say always, \'God be magnified!\'") — <em>gādal</em> (qal jussive: let God be made great/magnified): the doxological cry of those who love salvation — not "I am safe" but "God is great." <em>Tāmîd</em>: continually, always (Ps 34:1: "I will bless the LORD at all times; his praise shall continually be in my mouth").</p>',
    "5": '<p><strong>וַאֲנִי עָנִי וְאֶבְיוֹן</strong> (<em>waʾănî ʿānî wĕʾebyôn</em>, "But I am poor and needy") — the contrastive <em>waʾănî</em> (but I) as in Ps 69:29. <em>ʿĀnî</em> (afflicted/humble) and <em>ʾebyôn</em> (destitute/needy): the twin designations of the person who has no earthly resources and therefore turns entirely to God. In Ps 40:17 (the parallel) the same closing verse: the poverty is the qualification for trust, not the obstacle to it. <strong>אֱלֹהִים חוּשָׁה-לִּי</strong> (<em>ʾĕlōhîm ḥûshāh-llî</em>, "hurry to me, O God!") — the same <em>ḥûshāh</em> as v1: the psalm closes with the same urgent command that opened it. The emergency is maintained through to the final word — no resolution within the psalm itself, only urgent petition. <strong>עֶזְרִי וּמְפַלְּטִי אַתָּה</strong> (<em>ʿezrî ûmĕpallĕṭî ʾattāh</em>, "You are my help and my deliverer") — <em>ʿēzer</em>: help (the <em>ʿezer</em> of Gen 2:18 — the essential help); <em>pallaṭ</em> (piel participle: the one who causes escape, the liberator — from <em>pālaṭ</em>: to escape). <strong>יְהוָה אַל-תְּאַחַר</strong> (<em>yĕhwāh ʾal-tĕʾaḥar</em>, "O LORD, do not delay!") — <em>ʾāḥar</em>: to delay, to tarry. The final petition: opened with "hurry" (<em>ḥûshāh</em>), closed with "do not delay" (<em>ʾal-tĕʾaḥar</em>) — the same urgency in different words. The compressed Psalm 70 maintains emergency pitch from first word to last, unlike the extended Ps 40 from which it was drawn.</p>',
  },
}


def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 68-70 mkt-original written.')

if __name__ == '__main__':
    main()
